// Input is already an array of invoice items from weclapp node list (rootProperty extracted)
// The weclapp node returns items directly (not wrapped in .result)
const items = $input.all();
if (items.length === 0) return [];

const result = items.filter(item => {
  const inv = item.json;
  return !(inv.internalInvoiceNumber || '').startsWith('DUP-');
});

if (result.length === 0) return [];

return result.map((item, index) => {
  const inv = item.json;
  return {
    json: {
      id: inv.id,
      invoiceNumber: inv.invoiceNumber || '',
      internalInvoiceNumber: inv.internalInvoiceNumber || '',
      status: inv.status,
      grossAmount: inv.grossAmount || 0,
      netAmount: inv.netAmount || 0,
      supplierId: inv.supplierId || '',
      invoiceDate: inv.invoiceDate,
      dueDate: inv.dueDate,
      supplier: inv.recordAddress?.company || inv.recordAddress?.lastName || '',
      supplierVat: inv.vatRegistrationNumber || '',
      recordAddress: inv.recordAddress || {},
      itemCount: (inv.purchaseInvoiceItems || []).length,
      items: (inv.purchaseInvoiceItems || []).map(item => ({
        id: item.id,
        version: item.version,
        title: item.title || '',
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        netAmount: item.netAmount,
        grossAmount: item.grossAmount,
        taxId: item.taxId
      })),
      version: inv.version,
      createdViaOcr: inv.createdViaOcr || false,
      grossPrices: inv.grossPrices || false
    },
    pairedItem: { item: index }
  };
});

// ANTI-PATTERN NOTE: This Code node uses httpRequestWithAuthentication internally.
// Per project memory, this is unreliable. Flagged as HIGH bug in QA report.
// In a proper rebuild, this should be split into: GET party list (weclapp node) + Code + PUT update.
// Kept as-is to preserve workflow structure for QA analysis.

const invoice = $input.first().json;
const baseUrl = 'https://testhandel.weclapp.com/webapp/api/v1';

// Already has supplier? Pass through
if (invoice.supplierId) {
  return [{ json: { ...invoice, supplierAction: 'existing' }, pairedItem: { item: 0 } }];
}

// No supplier - try to find one
const company = invoice.supplier || invoice.recordAddress?.company || '';
if (!company) {
  return [{ json: { ...invoice, supplierAction: 'no_company_name' }, pairedItem: { item: 0 } }];
}

// Search by company name (ilike = case-insensitive contains)
const searchTerm = company.trim();
let parties = [];
try {
  const searchUrl = `${baseUrl}/party?company-ilike=${encodeURIComponent(searchTerm)}&supplier=true&pageSize=5&properties=id,company,supplierNumber,vatIdentificationNumber`;
  const response = await this.helpers.httpRequestWithAuthentication.call(this, 'weclappApi', {
    method: 'GET',
    url: searchUrl,
    json: true
  });
  parties = response.result || [];
} catch (e) {
  return [{ json: { ...invoice, supplierAction: 'search_error', supplierError: e.message }, pairedItem: { item: 0 } }];
}

if (parties.length === 1) {
  const party = parties[0];
  return [{ json: {
    ...invoice,
    supplierId: String(party.id),
    supplier: party.company || invoice.supplier,
    supplierAction: 'assigned',
    supplierMatch: party.company
  }, pairedItem: { item: 0 } }];
} else if (parties.length > 1) {
  const candidates = parties.map(p => p.company + ' (' + (p.supplierNumber || p.id) + ')').join(', ');
  return [{ json: { ...invoice, supplierAction: 'multiple_matches', supplierCandidates: candidates }, pairedItem: { item: 0 } }];
} else {
  return [{ json: { ...invoice, supplierAction: 'not_found' }, pairedItem: { item: 0 } }];
}

// DRY-RUN LIMITATION: Web search + party creation disabled.
// In production this calls Claude web_search and creates a new supplier.
// Skipped here to avoid creating real testhandel records.
const invoice = $input.first().json;
return [{ json: { ...invoice, supplierAction: 'websearch_skipped', skipAi: false }, pairedItem: { item: 0 } }];

// Get invoice data from whichever supplier path ran
let invoice;
try {
  invoice = $('Code: Skip Web Search (Dry Run)').item.json;
  if (!invoice.id) throw new Error('no id');
} catch {
  invoice = $('Code: Find & Assign Supplier').item.json;
}
const pdfItem = $input.first();

const result = {
  id: invoice.id,
  invoiceNumber: invoice.invoiceNumber || invoice.internalInvoiceNumber || '-',
  supplier: invoice.supplier || invoice.supplierMatch || 'Unbekannt',
  grossAmount: parseFloat(invoice.grossAmount) || 0,
  netAmount: parseFloat(invoice.netAmount) || 0,
  status: invoice.status,
  supplierId: invoice.supplierId || '',
  supplierAction: invoice.supplierAction || '',
  supplierCandidates: invoice.supplierCandidates || '',
  items: invoice.items || [],
  itemCount: invoice.itemCount || 0,
  version: invoice.version,
  grossPrices: invoice.grossPrices || false,
  createdViaOcr: invoice.createdViaOcr || false
};

// No PDF?
if (pdfItem.json.error || !pdfItem.binary?.data) {
  return [{ json: { ...result, skipAi: true, statusResult: 'no_pdf', aiSummary: 'Kein PDF in weclapp', aiIssues: [] }, pairedItem: { item: 0 } }];
}

const binaryData = await this.helpers.getBinaryDataBuffer.call(this, 0, 'data');

// ZugFerd / e-Invoice detection
const pdfRaw = binaryData.toString('latin1');
const hasZugFerd = /factur-x\.xml|zugferd-invoice\.xml|CrossIndustryInvoice|urn:factur-x|urn:zugferd/i.test(pdfRaw);
const isEInvoice = hasZugFerd && !result.createdViaOcr;
if (isEInvoice) {
  if (!result.supplierId) {
    return [{ json: { ...result, skipAi: true, isEInvoice: false, statusResult: 'review', shouldBook: false, aiSummary: 'E-Invoice (ZugFerd) aber kein Kreditor zugeordnet', aiIssues: ['kein_kreditor'], needsItemCorrection: false }, pairedItem: { item: 0 } }];
  }
  return [{ json: { ...result, skipAi: true, isEInvoice: true, statusResult: 'verified', shouldBook: true, aiSummary: 'E-Invoice (ZugFerd) - direkt gebucht', aiIssues: [], needsItemCorrection: false }, pairedItem: { item: 0 } }];
}

const pdfBase64 = binaryData.toString('base64');

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2048,
  system: 'Du extrahierst strukturierte Daten aus Rechnungs-PDFs. Antworte NUR mit JSON, kein Markdown, keine Erklaerung.',
  messages: [{
    role: 'user',
    content: [
      { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdfBase64 } },
      { type: 'text', text: 'Extrahiere alle Rechnungsdaten. Antworte mit JSON-Schema: {"issuerName":"...","issuerVat":"...","grossAmount":0,"netAmount":0,"invoiceNumber":"...","invoiceDate":"YYYY-MM-DD","lineItems":[],"confidence":0.0}' }
    ]
  }]
};

return [{ json: { ...result, anthropicBody: JSON.stringify(anthropicBody), skipAi: false }, pairedItem: { item: 0 } }];

const aiResponse = $input.first().json;
const invoice = $('Code: Prepare AI Request').item.json;
const minConfidence = parseFloat($('Constants').first().json.minConfidence) || 0.8;

const result = {
  id: invoice.id,
  invoiceNumber: invoice.invoiceNumber,
  supplier: invoice.supplier,
  grossAmount: invoice.grossAmount,
  netAmount: invoice.netAmount,
  status: invoice.status,
  supplierId: invoice.supplierId,
  supplierAction: invoice.supplierAction,
  supplierCandidates: invoice.supplierCandidates || '',
  items: invoice.items || [],
  version: invoice.version
};

let pdf = null;
try {
  if (aiResponse.error) throw new Error(aiResponse.error.message || 'API error');
  const text = (aiResponse.content || [])[0]?.text || '';
  const match = text.match(/\{[\s\S]*\}/);
  pdf = match ? JSON.parse(match[0]) : null;
} catch (e) {
  return [{ json: { ...result, statusResult: 'review', aiSummary: 'AI Parse-Fehler: ' + e.message, aiIssues: ['ai_error'], shouldBook: false, needsItemCorrection: false }, pairedItem: { item: 0 } }];
}

if (!pdf) {
  return [{ json: { ...result, statusResult: 'review', aiSummary: 'Keine Daten aus PDF extrahiert', aiIssues: ['no_extraction'], shouldBook: false, needsItemCorrection: false }, pairedItem: { item: 0 } }];
}

const confident = (pdf.confidence || 0) >= minConfidence;
result.pdfData = pdf;
result.pdfIssuerName = pdf.issuerName || '';
result.pdfIssuerVat = pdf.issuerVat || '';
result.grossAmountPdf = pdf.grossAmount;
result.aiConfidence = pdf.confidence;

if (!confident) {
  return [{ json: { ...result, statusResult: 'review', aiSummary: 'Confidence zu niedrig: ' + pdf.confidence, aiIssues: ['low_confidence'], shouldBook: false, needsItemCorrection: false }, pairedItem: { item: 0 } }];
}

// Compare line items
const erpItems = invoice.items || [];
const pdfItems = pdf.lineItems || [];
const taxMap = { 20: '3097', 10: '3098', 13: '3099', 0: '3100' };
let needsCorrection = false;
const correctedItems = erpItems.map((erp, idx) => {
  const pdfItem = pdfItems[idx] || null;
  const corrected = { id: erp.id, version: erp.version };
  let changed = false;
  if (pdfItem) {
    if (pdfItem.title && pdfItem.title !== erp.title) { corrected.title = pdfItem.title; changed = true; }
    if (pdfItem.quantity != null && Math.abs(pdfItem.quantity - erp.quantity) > 0.001) { corrected.quantity = pdfItem.quantity; changed = true; }
    if (pdfItem.unitPrice != null && Math.abs(pdfItem.unitPrice - erp.unitPrice) > 0.01) { corrected.unitPrice = pdfItem.unitPrice; changed = true; }
    if (pdfItem.netAmount != null && Math.abs(pdfItem.netAmount - erp.netAmount) > 0.01) { corrected.netAmount = pdfItem.netAmount; changed = true; }
    if (pdfItem.grossAmount != null && Math.abs(pdfItem.grossAmount - erp.grossAmount) > 0.01) { corrected.grossAmount = pdfItem.grossAmount; changed = true; }
    if (pdfItem.vatRate != null && taxMap[pdfItem.vatRate] && taxMap[pdfItem.vatRate] !== erp.taxId) { corrected.taxId = taxMap[pdfItem.vatRate]; changed = true; }
  }
  if (!erp.taxId) needsCorrection = true;
  if (changed) needsCorrection = true;
  return changed ? corrected : { id: erp.id, version: erp.version };
});

result.needsItemCorrection = needsCorrection;
result.correctedItems = correctedItems;
result.needsPartyCreation = false; // Dry-run: skip party creation

return [{ json: result, pairedItem: { item: 0 } }];

// Minimal rules engine for QA test - reads from Parse AI result
let prev;
try { prev = { ...$('Code: Parse AI & Prepare Corrections').item.json }; }
catch { prev = $input.first().json; }

// Respect early exits
if (prev.statusResult && prev.statusResult !== 'verified' && prev.shouldBook === false) {
  return [{ json: { ...prev, itemsCorrected: prev.needsItemCorrection || false }, pairedItem: { item: 0 } }];
}

let erpGross = parseFloat(prev.grossAmount) || 0;
let erpNet = parseFloat(prev.netAmount) || 0;
let version = prev.version;

if (prev.needsItemCorrection) {
  try {
    const refreshed = $('GET: Refreshed Invoice').item.json;
    erpGross = parseFloat(refreshed.grossAmount) || erpGross;
    erpNet = parseFloat(refreshed.netAmount) || erpNet;
    version = refreshed.version || version;
  } catch (e) {}
}

const pdf = prev.pdfData || {};
const pdfGross = parseFloat(pdf.grossAmount);
const pdfNet = parseFloat(pdf.netAmount);
const amountMatch = !isNaN(pdfGross) && (
  Math.abs(pdfGross - erpGross) <= 0.05 ||
  (!isNaN(pdfNet) && Math.abs(pdfNet - erpNet) <= 0.05)
);

const pdfInvNr = String(pdf.invoiceNumber || '').trim();
const erpInvNr = String(prev.invoiceNumber || '').trim();
const erpIsInternal = erpInvNr.startsWith('PI');
const invNrMatch = (pdfInvNr && erpInvNr && (pdfInvNr === erpInvNr || pdfInvNr.includes(erpInvNr) || erpInvNr.includes(pdfInvNr))) || erpIsInternal || !pdfInvNr;

const issues = [];
if (!amountMatch) issues.push('Betrag: PDF=' + (pdf.grossAmount || '?') + ' vs ERP=' + erpGross);
if (!invNrMatch) issues.push('RechNr: PDF=' + pdfInvNr + ' vs ERP=' + erpInvNr);
if (!prev.supplierId) issues.push('Kein Kreditor zugeordnet');

// DRY-RUN: never set shouldBook=true to prevent actual bookings on testhandel
const verified = amountMatch && invNrMatch && issues.length === 0;
const shouldBook = false; // DRY-RUN OVERRIDE

return [{ json: {
  id: prev.id,
  invoiceNumber: prev.invoiceNumber,
  supplier: prev.supplier,
  grossAmount: erpGross,
  netAmount: erpNet,
  status: prev.status,
  supplierId: prev.supplierId,
  supplierAction: prev.supplierAction,
  itemsCorrected: prev.needsItemCorrection || false,
  version: version,
  aiConfidence: prev.aiConfidence,
  statusResult: verified ? 'verified' : 'review',
  shouldBook: shouldBook,
  aiSummary: verified
    ? '[DRY-RUN] OK: Betrag ' + pdfGross + ' EUR, RechNr OK, Conf ' + prev.aiConfidence
    : issues.join('; '),
  aiIssues: issues,
  grossAmountPdf: pdf.grossAmount,
  dryRunNote: 'shouldBook forced to false - no real booking on testhandel'
}, pairedItem: { item: 0 } }];

let data;
try { data = $('Code: Rules Engine').item.json; }
catch { try { data = $('Code: Prepare AI Request').item.json; } catch { data = $input.first().json; } }
return [{ json: { ...data, statusResult: data.statusResult || 'review' }, pairedItem: { item: 0 } }];

const items = $input.all();

const booked = [], review = [], noPdf = [], errors = [];
const supplierAssigned = [], supplierCreated = [], supplierMissing = [], itemsCorrected = [];

for (const item of items) {
  const d = item.json;
  const entry = {
    invoiceNumber: d.invoiceNumber || d.internalInvoiceNumber || '-',
    supplier: d.supplier || 'Unbekannt',
    grossAmount: d.grossAmount || 0,
    aiSummary: d.aiSummary || '',
    aiIssues: d.aiIssues || [],
    supplierAction: d.supplierAction || '',
    itemsCorrected: d.itemsCorrected || false
  };

  if (d.supplierAction === 'assigned') supplierAssigned.push(entry);
  if (d.supplierAction === 'created') supplierCreated.push(entry);
  if (d.itemsCorrected) itemsCorrected.push(entry);

  switch (d.statusResult) {
    case 'booked': booked.push(entry); break;
    case 'verified': review.push({ ...entry, note: 'verified but dry-run' }); break;
    case 'review': review.push(entry); break;
    case 'no_pdf': noPdf.push(entry); break;
    case 'failed': errors.push({ ...entry, error: d.statusError }); break;
    default: break;
  }
}

if (items.length === 0) {
  return [{ json: { hasContent: false, summary: 'No invoices processed', items: [], booked, review, noPdf, supplierAssigned, supplierCreated, itemsCorrected, errors } }];
}

return [{ json: {
  hasContent: true,
  bookedCount: booked.length,
  reviewCount: review.length,
  noPdfCount: noPdf.length,
  supplierAssignedCount: supplierAssigned.length,
  supplierCreatedCount: supplierCreated.length,
  itemsCorrectedCount: itemsCorrected.length,
  errorCount: errors.length,
  booked, review, noPdf, supplierAssigned, supplierCreated, itemsCorrected, errors,
  dryRunNote: 'QA-R03 dry run - no real bookings made on testhandel'
} }];
